import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.DtwafDNl.js";const y=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"guide/security.md","filePath":"guide/security.md"}'),i={name:"guide/security.md"};function l(n,e,s,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="network-exposure-and-ports" tabindex="-1">Network exposure and ports <a class="header-anchor" href="#network-exposure-and-ports" aria-label="Permalink to &quot;Network exposure and ports&quot;">​</a></h2><p>Open only the ports you actually need:</p><ul><li><code>5080</code> UDP/TCP for SIP signaling.</li><li><code>10000-20000</code> UDP for RTP media.</li><li><code>3000</code> and <code>3001</code> only if you intentionally expose the web UI/API outside localhost.</li></ul><p>Keep all other service ports private unless you have a clear operational requirement.</p><h2 id="data-stored-locally" tabindex="-1">Data stored locally <a class="header-anchor" href="#data-stored-locally" aria-label="Permalink to &quot;Data stored locally&quot;">​</a></h2><p>Callytics is designed to keep runtime data on the host:</p><ul><li>Call logs and execution traces</li><li>Call recordings and audio assets</li><li>Extension and telephony configuration</li></ul><p>No application data is sent to an external hosted control plane by default. Data remains on your infrastructure unless you explicitly integrate external services.</p><h2 id="encryption-key" tabindex="-1">ENCRYPTION_KEY <a class="header-anchor" href="#encryption-key" aria-label="Permalink to &quot;ENCRYPTION_KEY&quot;">​</a></h2><p><code>ENCRYPTION_KEY</code> controls encryption at rest for the WireGuard relay private key:</p><ul><li>Optional in development.</li><li>Recommended in production.</li><li>When set, it should be a 64-character hex key.</li></ul><p>If unset or invalid, Callytics falls back to derived-key behavior. For production systems, set a strong explicit key and manage it as a secret.</p>',13)])])}const h=a(i,[["render",l]]);export{y as __pageData,h as default};
